#include <bits/stdc++.h>
using namespace std;
const int N=2e5+10;
int n,t[N],f[N],ans=N;
bool mark[N];
int father(int x){
    return f[x]==x?x:father(f[x]);
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&t[i]);
        f[i]=i;
    }
    for(int i=1;i<=n;i++){
        if(father(i)!=father(t[i]))
            f[i]=t[i];
        else{
            bool flag=false;
            int sum=1,x=i;
            while(f[x]!=x){
                if(x==t[i]){
                    ans=min(ans,sum);
                    flag=true;
                    break;
                }
                mark[x]=1,x=f[x],sum++;
            }
            if(flag)
                break;
            sum=1,mark[x]=1,x=t[i];
            while(1){
                if(mark[x]){
                    ans=min(ans,sum);
                    flag=true;
                    break;
                }
                x=f[x],sum++;
            }
        }
    }
    printf("%d",ans);
    return 0;
}
